INSERT INTO `Event` VALUES
('03990335-b71d-402d-8c5f-6110f0aa934b','Weaver Street Market will be at the Cary Pimento Cheese Festival!','<p>Weaver Street Market will be at the Pimento Cheese Festival in Cary on April 11th from 11am to 4pm.  Learn more about this event here: <a href=\"https://www.carync.gov/recreation-enjoyment/events/special-events/pimento-cheese-festival\" target=\"_blank\" rel=\"noopener\">Pimento Cheese Festival</a></p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo.png\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-300x68.png\" alt=\"\" width=\"397\" height=\"90\" class=\"alignnone  wp-image-32408\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-300x68.png 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-1024x233.png 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-768x174.png 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-1536x349.png 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo-600x136.png 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/04/cary-pimento-cheese-festival-logo.png 1920w\" sizes=\"auto, (max-width: 397px) 100vw, 397px\" /></a></p>','2026-04-11 15:00:00.000','2026-04-11 20:00:00.000','SCHEDULED','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32407,'https://www.weaverstreetmarket.coop/event/weaver-street-market-will-be-at-the-cary-pimento-cheese-festival/','2026-04-08 13:48:36.959','2026-04-08 13:48:36.959','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('095dd9fa-7b7a-47b2-9221-6f337e56ef76','Weaver Street Market and Equal Exchange Webinar','<h3><span style=\"color: #800080;\">Weaver Street Market and Equal Exchange Webinar</span></h3>\n<div></div>\n<p><span style=\"color: #000000;\">We invite you to register for a virtual Fireside Chat with our General Manager, James Watts, on Thursday, February 19th from 6:30-7:30 PM. You’ll learn how Co-op to Co-op trade works between Equal Exchange and Weaver Street Market. And equally as important, you’ll hear about ways you as co-op owners have a role to play in this effort. Register for the event <strong><a href=\"https://assets-usa.mkt.dynamics.com/ed9ebe7d-dc0c-4310-a21d-bd4696e1be5e/digitalassets/standaloneforms/8cdb4d2b-9dfb-f011-8407-7c1e527ee3ba#_msdynmkt_donottrack=0,_msdynmkt_linkid=8f807ae8-8c4a-43fd-8b0c-fedcf604ed01\" target=\"_blank\" style=\"color: #000000;\" rel=\"noopener\">here</a></strong>.</span><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/CoffeeBananas_tryptych.jpg\" alt=\"\" width=\"600\" height=\"157\" class=\"wp-image-32013 size-full alignnone\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/CoffeeBananas_tryptych.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/CoffeeBananas_tryptych-300x79.jpg 300w\" sizes=\"auto, (max-width: 600px) 100vw, 600px\" /> <img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/Tea_tryptych.jpg\" alt=\"\" width=\"548\" height=\"157\" class=\"alignnone wp-image-32011 \" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/Tea_tryptych.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/Tea_tryptych-300x86.jpg 300w\" sizes=\"auto, (max-width: 548px) 100vw, 548px\" /><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/equal-excahne-logo.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/equal-excahne-logo-300x156.jpg\" alt=\"\" width=\"319\" height=\"166\" class=\"alignnone wp-image-31999\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/equal-excahne-logo-300x156.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/02/equal-excahne-logo.jpg 600w\" sizes=\"auto, (max-width: 319px) 100vw, 319px\" /></a></p>','2026-02-19 23:30:00.000','2026-02-20 00:30:00.000','PAST','ec7a5d02-565b-417d-bcdf-9846cfd46df9','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31997,'https://www.weaverstreetmarket.coop/event/weaver-street-market-and-equal-exchange-webinar/','2026-04-08 13:48:36.937','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('0ec611c7-3c4f-4a09-ac53-f42d0afe45d8','Hillsborough Lunch  Learn: Getting to the Heart of Cardiovascular Disease: A Natural Approach to Prevention and Solutions','<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-225x300.jpg\" alt=\"\" width=\"225\" height=\"300\" class=\"size-medium wp-image-31849 alignleft\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-225x300.jpg 225w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-768x1024.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-1152x1536.jpg 1152w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-1536x2048.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-600x800.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/01/Head-Shot-Best-10-22-scaled.jpg 1920w\" sizes=\"auto, (max-width: 225px) 100vw, 225px\" /></a>Come and grab lunch with us at our Hillsborough store and join us in the cafe for a free Lunch &amp; Learn on &#8220;Getting to the Heart of Cardiovascular Disease: A Natural Approach to Prevention and Solutions.&#8221; Presenter Carole Hoffman has had a personal focus in holistic health and healing for over 30 years. She studied under a holistic nurse for 23 years and was certified in Neural DepolarizationTM nervous system therapy, which she focused on in her private practice for 8 years. She then broadened her holistic endeavors by expanding into the field of nutrition, where she acquired over 600 hours of nutritional education, while studying under over a dozen experts in their field. She has been a nutritional advisor to other holistic healthcare professionals on their tough patient cases, and is currently in private practice as a nutritional consultant. She works with a wide spectrum of conditions from hormonal to gastro-intestinal and from metabolic to toxicity, working to eliminate dysfunction and bring the body back into a fully functional state of health. Her belief is that when the body is functioning properly it has the ability to heal practically anything. <a href=\"https://www.carolehoffman.com/\">Carole Hoffman | Natural Health Alternatives &#8211; NC | Home</a></p>','2026-02-26 16:00:00.000','2026-02-26 17:30:00.000','PAST','f62716b6-696d-4431-965d-64a485eb172e','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31848,'https://www.weaverstreetmarket.coop/event/hillsborough-lunch-learn-getting-to-the-heart-of-cardiovascular-disease-a-natural-approach-to-prevention-and-solutions/','2026-04-08 13:48:36.940','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
