('28b91289-7a65-4518-ba3a-8f9888b0f35e','Italian Cheese  Wine Pop Up  Raleigh','<p><span>Join us at </span><strong>Weaver Street Market in Raleigh</strong><span> on </span><strong>June 6, 2026 at 3:00 PM </strong><span> for a chill afternoon of tasting some amazing </span><strong>Italian cheeses</strong><span> and </span><strong>wines</strong><span>. It’s the perfect chance to discover new flavors, chat with fellow food lovers, and enjoy a relaxed vibe. Don’t miss out on this tasty pop-up event — see you there! Tickets available now! Two sessions &#8211; 3pm to 4pm and 4pm to 5pm</span></p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-scaled.jpg\"><span>.</span><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg\" alt=\"\" width=\"300\" height=\"200\" class=\"size-medium wp-image-32262\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1024x683.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-768x512.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1536x1024.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-2048x1365.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-600x400.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-06-06 19:00:00.000','2026-06-06 21:00:00.000','SCHEDULED','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32266,'https://www.weaverstreetmarket.coop/event/italian-cheese-wine-pop-up-raleigh/','2026-04-08 13:48:36.991','2026-04-08 13:48:36.991','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('3094276f-f1cb-4cc0-8e8e-367db386fa58','Join us for Vege-Palooza!','<p>PRE-SALE TICKETS ARE SOLD OUT &#8211; BUT WALK-INS ARE WELCOME AT 12 NOON! Join us for Vege-Palooza at our Raleigh store! Looking to get more veggies into your diet? Join us from 11am to 1pm at our Raleigh store to find out more about vegetarian and vegan products, sample some great plant-based recipes, let the kids pot their own veggie seedlings, and learn how to add more plant-based cooking and eating to your life! FREE event! Reserve your space now!</p>','2026-02-28 16:00:00.000','2026-02-28 18:00:00.000','PAST','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31598,'https://www.weaverstreetmarket.coop/event/join-us-for-vege-palooza/','2026-04-08 13:48:36.942','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
