('c5ff37df-28d4-4e84-9245-3ee54a75193f','Spanish Cheese and Wine Pop Up  Southern Village','<p><span data-teams=\"true\">PRE-SALE TICKETS ARE SOLD OUT FOR THIS EVENT, BUT WALK-INS ARE WELCOME AFTER 4PM. WALK-IN TICKET CAN BE PURCHASED AT THE REGISTER. Join us for a Spanish Cheese Pop Up Tasting in our Southern Village store! On Saturday, January 10th we will take over the Southern Village Cafe from 3 to 5pm. Join us for this fun pop up tasting featuring delicious, artisanal Spanish cheeses paired with hand-picked Spanish Wines, and fun accompaniments. Tickets on sale now!</span></p>','2026-01-10 20:00:00.000','2026-01-10 22:00:00.000','PAST','c49485e4-1a2b-479c-b1e7-303298730bf6','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31485,'https://www.weaverstreetmarket.coop/event/spanish-cheese-and-wine-pop-up-southern-village/','2026-04-08 13:48:36.931','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('c653d646-72b1-4409-a504-04800c5c1e57','Italian Wine  Cheese Pop Up  Carrboro Store','<p><span>Join us at </span><strong>Weaver Street Market in Carrboro</strong><span> on <strong>May 30</strong></span><strong>, 2026 at 3:00 PM </strong><span> for a chill afternoon of tasting some amazing </span><strong>Italian cheeses</strong><span> and </span><strong>wines</strong><span>. It’s the perfect chance to discover new flavors, chat with fellow food lovers, and enjoy a relaxed vibe. Don’t miss out on this tasty pop-up event — see you there! Tickets available now! Two sessions &#8211; 3pm to 4pm and 4pm to 5pm</span></p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg\" alt=\"\" width=\"300\" height=\"200\" class=\"size-medium wp-image-32262\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1024x683.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-768x512.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1536x1024.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-2048x1365.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-600x400.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-05-30 19:00:00.000','2026-05-30 21:00:00.000','SCHEDULED','7b0ecc8b-704c-4df4-9128-53e85ac7e1cd','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32261,'https://www.weaverstreetmarket.coop/event/italian-wine-cheese-pop-up-carrboro-store/','2026-04-08 13:48:36.987','2026-04-08 13:48:36.987','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('cd174ffc-9343-4035-9442-eafa0f0d5315','Raleigh Friday Night Tasting Event','<p>Join us for samplings in our Raleigh store on Friday nights from 5 to 7pm!<a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-scaled.png\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-279x300.png\" alt=\"\" width=\"279\" height=\"300\" class=\"alignnone size-medium wp-image-32135\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-279x300.png 279w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-953x1024.png 953w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-768x825.png 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-1430x1536.png 1430w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-1907x2048.png 1907w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-600x644.png 600w\" sizes=\"auto, (max-width: 279px) 100vw, 279px\" /></a></p>','2026-04-03 21:00:00.000','2026-04-03 23:00:00.000','PAST','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32133,'https://www.weaverstreetmarket.coop/event/raleigh-friday-night-tasting-event/','2026-04-08 13:48:36.951','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('d1a5c6c7-339b-41c2-9dad-dae39e1e2f9d','Asian Dumpling 101: Learn Dumpling Making with Moore Dumplings','<div class=\"undefined\">\n<div class=\"summary\">Hongie from Moore Dumplings will teach us how to cook Asian dumplings in a variety of quick and easy methods.</div>\n</div>\n<div class=\"structured-content-rich-text\">\n<div class=\"eds-text--left\">\n<p>Join us at our Raleigh store for a quick trip to China’s Sichuan province, famous among world cuisines for its bold, punchy flavors. Hongie from Moore Dumplings will teach us how to cook Asian dumplings in a variety of quick and easy methods. She will talk about spices used in Sichuanese cuisine and teach us how to make delicious, exotic sauces from everyday ingredients in your cupboard. Please join us for this journey up the Yangtse and bring your appetite!</p>\n<p>Tickets on sale now!</p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/IMG_2238-1.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/IMG_2238-1-248x300.jpg\" alt=\"\" width=\"248\" height=\"300\" class=\"alignnone size-medium wp-image-32238\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/IMG_2238-1-248x300.jpg 248w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/IMG_2238-1-600x725.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/IMG_2238-1.jpg 612w\" sizes=\"auto, (max-width: 248px) 100vw, 248px\" /></a></p>\n</div>\n</div>','2026-05-22 22:00:00.000','2026-05-23 00:00:00.000','SCHEDULED','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32237,'https://www.weaverstreetmarket.coop/event/asian-dumpling-101-learn-dumpling-making-with-moore-dumplings/','2026-04-08 13:48:36.982','2026-04-08 13:48:36.982','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('d4b305ac-954a-4061-b50c-6e8adb715b2b','Farm to Fork Tour: Winter Shopping with the Chef','Winter shopping tour with the chef at our Raleigh store.','2026-03-15 18:00:00.000','2026-03-15 20:00:00.000','PAST','9a0e3c1e-50f7-446c-bb6f-8b38f59af78d',NULL,NULL,NULL,NULL,'2026-02-25 13:51:32.255','2026-04-08 18:14:07.628',NULL,NULL,NULL),
('d76d5f9c-d436-4fd4-9141-90e7b11a8a12','Spanish Cheese and Wine Pop Up  Carrboro','<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-300x200.jpg\" alt=\"\" width=\"300\" height=\"200\" class=\"size-medium wp-image-30605\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-300x200.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-1024x684.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-768x513.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-1536x1026.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-2048x1368.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/07/iStock-1148833834-600x401.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>\n<p><span data-teams=\"true\">PRE-SALE TICKETS ARE SOLD OUT FOR THIS EVENT, BUT WALK-INS ARE WELCOME AFTER 4PM. WALK-IN TICKET CAN BE PURCHASED AT THE REGISTER. </span><span data-teams=\"true\">Join us for a Spanish Cheese Pop Up Tasting in our Carrboro store! On Sunday, January 11th we will take over the Carrboro Cafe from 3 to 5pm. Join us for this fun pop up tasting featuring delicious, artisanal Spanish cheeses paired with hand-picked Spanish Wines, and fun accompaniments. Tickets on sale now!</span></p>','2026-01-11 20:00:00.000','2026-01-11 22:00:00.000','PAST','7b0ecc8b-704c-4df4-9128-53e85ac7e1cd','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31487,'https://www.weaverstreetmarket.coop/event/spanish-cheese-and-wine-pop-up-carrboro/','2026-04-08 13:48:36.933','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('def6058f-d1f6-498b-b700-773ab2381492','Raleigh Friday Night Sampling Event','<p>Join us for samplings in our Raleigh store on Friday nights from 5 to 7pm!<a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-scaled.png\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-279x300.png\" alt=\"\" width=\"279\" height=\"300\" class=\"alignnone size-medium wp-image-32135\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-279x300.png 279w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-953x1024.png 953w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-768x825.png 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-1430x1536.png 1430w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-1907x2048.png 1907w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Friday-night-Tastings-RL-SOCIAL-2-600x644.png 600w\" sizes=\"auto, (max-width: 279px) 100vw, 279px\" /></a></p>','2026-04-10 21:00:00.000','2026-04-10 23:00:00.000','SCHEDULED','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32138,'https://www.weaverstreetmarket.coop/event/raleigh-friday-night-sampling-event/','2026-04-08 13:48:36.957','2026-04-08 13:48:36.957','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('e3c5e9d7-1e23-4e86-b534-d64929a80a23','Southern Village Wine Fair','<p>Join us for our Spring Wine Fair on 4/5 from 3 to 5pm on our Southern Village Patio!</p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-300x288.jpg\" alt=\"\" width=\"300\" height=\"288\" class=\"alignnone size-medium wp-image-30020\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-300x288.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-1024x984.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-768x738.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-1536x1475.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-2048x1967.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-600x576.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-04-05 19:00:00.000','2026-04-05 21:00:00.000','PAST','c49485e4-1a2b-479c-b1e7-303298730bf6','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32144,'https://www.weaverstreetmarket.coop/event/southern-village-wine-fair-3/','2026-04-08 13:48:36.954','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('e564aba7-f396-461c-8874-d5802f5638d5','Italian Wine  Cheese Pop Up  Southern Village','<p><span>Join us at </span><strong>Weaver Street Market in Southern Village</strong><span> on <strong>May 31</strong></span><strong>, 2026 at 3:00 PM </strong><span> for a chill afternoon of tasting some amazing </span><strong>Italian cheeses</strong><span> and </span><strong>wines</strong><span>. It’s the perfect chance to discover new flavors, chat with fellow food lovers, and enjoy a relaxed vibe. Don’t miss out on this tasty pop-up event — see you there! Tickets available now! Two sessions &#8211; 3pm to 4pm and 4pm to 5pm</span></p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg\" alt=\"\" width=\"300\" height=\"200\" class=\"size-medium wp-image-32262\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-300x200.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1024x683.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-768x512.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-1536x1024.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-2048x1365.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/iStock-185185623-600x400.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-05-31 19:00:00.000','2026-05-31 21:00:00.000','SCHEDULED','c49485e4-1a2b-479c-b1e7-303298730bf6','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32264,'https://www.weaverstreetmarket.coop/event/italian-wine-cheese-pop-up-southern-village/','2026-04-08 13:48:36.988','2026-04-08 13:48:36.988','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('e9486d85-fc84-4726-93ae-586d96c6a8f1','St. Patricks Day Celebration','<p>DIDN&#8217;T GET A TICKET? NO PROBLEM! WALK-INS WELCOME AT 6PM! Join us at our Southern Village store to celebrate St. Patrick&#8217;s Day in style! Invite some friends, dress in green, enjoy our Saint Pat&#8217;s selfie station, hang out for a while and share some treats with us from 5pm to 7pm &#8211; drop in and enjoy! Reserve your space below!</p>','2026-03-17 21:00:00.000','2026-03-17 23:00:00.000','PAST','c49485e4-1a2b-479c-b1e7-303298730bf6','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31618,'https://www.weaverstreetmarket.coop/event/st-patricks-day-celebration/','2026-04-08 13:48:36.948','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('eeb1420b-f373-43ec-9e7a-a2105de89bf5','Breakfast for Dinner: Southern Biscuits and Gravy Class','<p>Join&nbsp;our&nbsp;Southern&nbsp;Biscuits&nbsp;and&nbsp;Gravy&nbsp;class&nbsp;for&nbsp;a&nbsp;fun&nbsp;breakfast-for-dinner&nbsp;experience.</p>','2026-03-16 23:00:00.000','2026-03-17 01:00:00.000','PAST','9a0e3c1e-50f7-446c-bb6f-8b38f59af78d','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,NULL,NULL,'2026-02-25 13:51:32.257','2026-04-08 18:56:31.670',NULL,'4b272e69-913e-428c-ac0c-8f3431600bca','<p></p>'),
('f0aedba4-8f20-48b3-9df6-ad97e9a2c039','SOLD OUT! Sushi with Sujin','<p>THIS EVENT IS SOLD OUT. PLEASE CHECK OUT OUR OTHER EVENTS! Are you a sushi lover? Are you curious about sushi? We have the class for you! Join us for a fun-filled, hands-on, sushi making class with Sujin Han. Get ready to dive into the world of sushi as Sujin &#8211; who has been making sushi for over 25 years and has been a valued Weaver Street Market partner since 2004 &#8211; leads you through the art of sushi making. Learn pro techniques and tips, learn how to prepare that all-important, perfectly seasoned sushi rice and gain an understanding of everything from filling, to cutting, to plating. Sujin will guide you through each step, demystify sushi making, and make it approachable and fun for everyone! Be sure to come hungry because you will be able to enjoy everything you make in class! Tickets on sale now!</p>','2026-03-13 22:00:00.000','2026-03-14 00:00:00.000','PAST','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31610,'https://www.weaverstreetmarket.coop/event/sushi-with-sujin-2/','2026-04-08 13:48:36.944','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('f25be00b-21c4-49c0-a2f1-d726cdc54f25','Raleigh Lunch & Learn: Getting to the Heart of Cardiovascular Disease','A free lunch and learn event focusing on cardiovascular disease at the Raleigh location.','2026-02-26 16:00:00.000','2026-02-26 17:00:00.000','PAST','9a0e3c1e-50f7-446c-bb6f-8b38f59af78d','4b272e69-913e-428c-ac0c-8f3431600bca',NULL,NULL,NULL,'2026-02-25 13:51:32.247','2026-04-08 18:14:07.628',NULL,'4b272e69-913e-428c-ac0c-8f3431600bca',NULL),
('f4e17b3a-9b4c-483b-8b09-58bb9208666f','SOLD OUT! Winter Mocktail Mixology Class','<p>SOLD OUT! Please check out our other classes and events! Join Weaver Street Market and Devil&#8217;s Foot Beverage Company for a Dry January mocktail mixology class! Learn to craft sophisticated and delicious booze-free drinks that will warm up a winter evening! Hands-on fun for beginners and experienced sippers! Tickets on sale now!</p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-300x200.jpg\" alt=\"\" width=\"300\" height=\"200\" class=\"size-medium wp-image-31482 alignleft\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-300x200.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-1024x683.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-768x512.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-1536x1024.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville-600x400.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/12/Devils-Foot-on-Making-It-inAsheville.jpg 1560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-01-09 23:00:00.000','2026-01-10 01:00:00.000','PAST','d3ea6f92-2fd4-4134-9d28-622256b37d42','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,31481,'https://www.weaverstreetmarket.coop/event/winter-mocktail-mixology-class/','2026-04-08 13:48:36.928','2026-04-08 18:14:07.628','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('fae9d833-1d5d-48f2-99a1-ef4fedcfe2ab','Sip  Create: Mixed Media Flower Collage with Barbara Younger','<p>Join us at Weaver Street Market on May 2, 2026, at 3:00 PM for a fun and relaxing afternoon with the amazing Barbara Younger. Bring your creativity, enjoy some good fun, and let your imagination run wild in this hands-on Mixed Media Flower Collage workshop. No experience needed &#8211; just come ready to sip, create, and have a great time.</p>\n<p>Barbara Younger&#8217;s art celebrates what&#8217;s quirky, upbeat, and intriguing about our world. Her bold and bright acrylic paintings, gel prints, and mixed media pieces are popular with both kids and adults. You can see her work at the Hillsborough Arts Council and Gift Shop and Solgarden in Mebane, or by making an appointment to visit her home studio. Follow Barbara on Instagram at instagram.com/barbarayounger/</p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-233x300.jpg\" alt=\"\" width=\"233\" height=\"300\" class=\"alignnone size-medium wp-image-32351\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-233x300.jpg 233w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-796x1024.jpg 796w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-768x989.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-1193x1536.jpg 1193w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase-600x772.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Younger-Polka-Dot-Vase.jpg 1574w\" sizes=\"auto, (max-width: 233px) 100vw, 233px\" /></a> <a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-236x300.jpg\" alt=\"\" width=\"236\" height=\"300\" class=\"alignnone size-medium wp-image-32352\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-236x300.jpg 236w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-805x1024.jpg 805w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-768x977.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-1208x1536.jpg 1208w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life-600x763.jpg 600w, https://www.weaverstreetmarket.coop/wp-content/uploads/2026/03/Green-Stamp-Still-Life.jpg 1587w\" sizes=\"auto, (max-width: 236px) 100vw, 236px\" /></a></p>','2026-05-02 19:00:00.000','2026-05-02 21:00:00.000','SCHEDULED','7b0ecc8b-704c-4df4-9128-53e85ac7e1cd','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32350,'https://www.weaverstreetmarket.coop/event/sip-create-mixed-media-flower-collage-with-barbara-younger/','2026-04-08 13:48:36.973','2026-04-08 13:48:36.973','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL),
('fd7cf850-3d70-4359-9167-9020f0c387f4','Hillsborough Wine Fair','<p>Join us for our Spring Wine Fair in Hillsborough on 4/11 from 3 to 5pm!</p>\n<p><a href=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" src=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-300x288.jpg\" alt=\"\" width=\"300\" height=\"288\" class=\"alignnone size-medium wp-image-30020\" srcset=\"https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-300x288.jpg 300w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-1024x984.jpg 1024w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-768x738.jpg 768w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-1536x1475.jpg 1536w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-2048x1967.jpg 2048w, https://www.weaverstreetmarket.coop/wp-content/uploads/2025/04/WineSaleandFairs5-600x576.jpg 600w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></a></p>','2026-04-11 19:00:00.000','2026-04-11 21:00:00.000','SCHEDULED','f62716b6-696d-4431-965d-64a485eb172e','b0e75286-eb68-4763-b237-37363ed93aa7',NULL,32151,'https://www.weaverstreetmarket.coop/event/hillsborough-wine-fair-3/','2026-04-08 13:48:36.960','2026-04-08 13:48:36.960','b0e75286-eb68-4763-b237-37363ed93aa7','b0e75286-eb68-4763-b237-37363ed93aa7',NULL);
