('a71a2dc7-d92a-49ea-874d-5989159ee150','Coomer Band','Brand','Local bluegrass band.','coomerband.com','EQUAL EXCHANGE',NULL,'2026-02-24 21:38:07.948','2026-02-25 16:38:38.570',NULL,'4b272e69-913e-428c-ac0c-8f3431600bca'),
